  4429→template <typename T, FMT_ENABLE_IF(std::is_integral<T>::value)>
  4430→FMT_NODISCARD FMT_CONSTEXPR_STRING auto to_string(T value) -> std::string {
  4431→  // The buffer should be large enough to store the number including the sign
  4432→  // or "false" for bool.
  4433→  char buffer[max_of(detail::digits10<T>() + 2, 5)];
