## 3. THE TYPE-ERASED INTERFACE: vformat AND format_args

### 3.1 fmt::vformat - The Type-Erased Entry Point

**Location**: format.h (lines ~4405), format-inl.h (lines ~1455)

There are two main vformat signatures:

```cpp
// Signature 1: Basic vformat (from format.h, ~line 4405)
FMT_API auto vformat(string_view fmt, format_args args) -> std::string;

// Signature 2: Locale-aware vformat (from format.h, ~line 4367)
inline auto vformat(locale_ref loc, string_view fmt, format_args args) 
    -> std::string {
  auto buf = memory_buffer();
  detail::vformat_to(buf, fmt, args, loc);
  return {buf.data(), buf.size()};
}
```

**How it works with vargs**:
- `vformat()` takes a `format_args` object (type-erased)
- Arguments are collected via the `vargs<T...>` template alias which creates a `format_arg_store`
- The `format_args` is created either from `format_arg_store` (compile-time) or `dynamic_format_arg_store` (runtime)

**Implementation flow** (format-inl.h):
```cpp
FMT_FUNC void vformat_to(buffer<char>& buf, string_view fmt, format_args args,
                         locale_ref loc) {
  auto out = appender(buf);
  if (fmt.size() == 2 && equal2(fmt.data(), "{}"))
    return args.get(0).visit(default_arg_formatter<char>{out});
  parse_format_string(fmt,
      format_handler<>{parse_context<>(fmt), {out, args, loc}});
}
```

### 3.2 fmt::format_args - The Type-Erased Argument Container

**Location**: base.h (lines ~2467)

```cpp
template <typename Context> class basic_format_args {
 private:
  ullong desc_;  // Descriptor with type info
  union {
    const detail::value<Context>* values_;    // For packed args (≤15 args)
    const basic_format_arg<Context>* args_;   // For unpacked args
  };

  constexpr auto is_packed() const -> bool {
    return (desc_ & detail::is_unpacked_bit) == 0;
  }
  constexpr auto has_named_args() const -> bool {
    return (desc_ & detail::has_named_args_bit) != 0;
  }

 public:
  // Constructor from dynamic_format_arg_store
  constexpr basic_format_args(const format_arg* args, int count,
                              bool has_named = false)
      : desc_(detail::is_unpacked_bit | detail::to_unsigned(count) |
              (has_named ? +detail::has_named_args_bit : 0)),
        args_(args) {}

  // Retrieve arg by index
  FMT_CONSTEXPR auto get(int id) const -> format_arg {
    auto arg = format_arg();
    if (!is_packed()) {
      if (id < max_size()) arg = args_[id];
      return arg;
    }
    if (unsigned(id) >= detail::max_packed_args) return arg;
    arg.type_ = type(id);
    if (arg.type_ != detail::type::none_type) arg.value_ = values_[id];
    return arg;
  }

  // Retrieve arg by name (for named arguments)
  template <typename Char>
  auto get(basic_string_view<Char> name) const -> format_arg {
    int id = get_id(name);
    return id >= 0 ? get(id) : format_arg();
  }
};
```

**Key constants**:
```cpp
enum { packed_arg_bits = 4 };
enum { max_packed_args = 62 / packed_arg_bits };  // 15 args max for packed
enum : ullong { is_unpacked_bit = 1ULL << 63 };
enum : ullong { has_named_args_bit = 1ULL << 62 };
```

### 3.3 fmt::basic_format_arg<Context> - Individual Type-Erased Argument

**Location**: base.h (lines ~2386)

```cpp
template <typename Context> class basic_format_arg {
 private:
  detail::value<Context> value_;  // Stores the actual data
  detail::type type_;              // Type discriminator

 public:
  class handle {
    detail::custom_value<Context> custom_;
    explicit handle(detail::custom_value<Context> custom) : custom_(custom) {}
    void format(parse_context<char_type>& parse_ctx, Context& ctx) const {
      custom_.format(custom_.value, parse_ctx, ctx);
    }
  };

  // Visit method - dispatches to formatter based on type
  template <typename Visitor>
  FMT_CONSTEXPR FMT_INLINE auto visit(Visitor&& vis) const 
      -> decltype(vis(0)) {
    using detail::map;
    switch (type_) {
    case detail::type::none_type:        break;
    case detail::type::int_type:         return vis(value_.int_value);
    case detail::type::uint_type:        return vis(value_.uint_value);
    case detail::type::long_long_type:   return vis(value_.long_long_value);
    case detail::type::ulong_long_type:  return vis(value_.ulong_long_value);
    case detail::type::int128_type:      return vis(map(value_.int128_value));
    case detail::type::uint128_type:     return vis(map(value_.uint128_value));
    case detail::type::bool_type:        return vis(value_.bool_value);
    case detail::type::char_type:        return vis(value_.char_value);
    case detail::type::float_type:       return vis(value_.float_value);
    case detail::type::double_type:      return vis(value_.double_value);
    case detail::type::long_double_type: return vis(value_.long_double_value);
    case detail::type::cstring_type:     return vis(value_.string.data);
    case detail::type::string_type:      return vis(value_.string.str());
    case detail::type::pointer_type:     return vis(value_.pointer);
    case detail::type::custom_type:      return vis(handle(value_.custom));
    }
    return vis(monostate());
  }
};
```

